import React, { useState, useEffect } from 'react';
import bridge from '@vkontakte/vk-bridge';
import './App.css';

const STORAGE_KEY = 'todo_app_data';

const App = () => {
  const [tasks, setTasks] = useState([]);
  const [newTask, setNewTask] = useState('');
  const [editingId, setEditingId] = useState(null);
  const [editText, setEditText] = useState('');
  const [userInfo, setUserInfo] = useState(null);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('all');
  const [error, setError] = useState(null);
  const [initAttempts, setInitAttempts] = useState(0);

  useEffect(() => {
    console.log('App mounted, starting initialization...');
    
    const initApp = async () => {
      console.log('initApp started, attempt:', initAttempts + 1);
      
      try {
        // Устанавливаем тестового пользователя сразу для разработки
        console.log('Setting test user');
        setUserInfo({
          first_name: 'Тестовый',
          last_name: 'Пользователь',
          photo_100: 'https://vk.com/images/camera_100.png'
        });

        // Загружаем задачи из localStorage
        console.log('Loading tasks from localStorage');
        let savedTasks = [];
        
        try {
          const localData = localStorage.getItem(STORAGE_KEY);
          console.log('localStorage data:', localData);
          
          if (localData) {
            savedTasks = JSON.parse(localData);
            console.log('Parsed tasks:', savedTasks);
          } else {
            // Добавим тестовые задачи для демонстрации
            savedTasks = [
              {
                id: Date.now() - 1000,
                text: 'Пример задачи 1',
                completed: false,
                createdAt: new Date().toISOString()
              },
              {
                id: Date.now() - 2000,
                text: 'Пример задачи 2',
                completed: true,
                createdAt: new Date().toISOString()
              }
            ];
            console.log('Created test tasks:', savedTasks);
          }
        } catch (localError) {
          console.error('Error loading from localStorage:', localError);
        }

        setTasks(savedTasks);
        console.log('Tasks set, loading complete');

      } catch (error) {
        console.error('Error in initApp:', error);
        setError('Произошла ошибка при загрузке приложения: ' + error.message);
      } finally {
        console.log('Setting loading to false');
        setLoading(false);
      }
    };

    // Добавим таймаут на случай, если инициализация зависнет
    const timeoutId = setTimeout(() => {
      console.log('Initialization timeout - forcing loading to false');
      setLoading(false);
      setError('Инициализация заняла слишком много времени');
    }, 5000);

    initApp();

    return () => {
      console.log('Cleanup timeout');
      clearTimeout(timeoutId);
    };
  }, []); // Пустой массив зависимостей

  // Добавим useEffect для отслеживания изменений состояния
  useEffect(() => {
    console.log('State updated:', { loading, tasks: tasks.length, error });
  }, [loading, tasks, error]);

  const saveTasks = async (updatedTasks) => {
    console.log('Saving tasks:', updatedTasks);
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(updatedTasks));
      console.log('Tasks saved to localStorage');
      
      // Пробуем VK Storage только если доступен
      try {
        if (window.bridge) {
          await bridge.send('VKWebAppStorageSet', {
            key: STORAGE_KEY,
            value: JSON.stringify(updatedTasks)
          });
          console.log('Tasks saved to VK Storage');
        }
      } catch (vkError) {
        console.log('VK Storage not available:', vkError);
      }
    } catch (error) {
      console.error('Error saving tasks:', error);
    }
  };

  const addTask = async (e) => {
    e.preventDefault();
    if (!newTask.trim()) return;

    const newTaskObj = {
      id: Date.now(),
      text: newTask.trim(),
      completed: false,
      createdAt: new Date().toISOString()
    };

    const updatedTasks = [...tasks, newTaskObj];
    setTasks(updatedTasks);
    await saveTasks(updatedTasks);
    setNewTask('');
  };

  const deleteTask = async (id) => {
    const updatedTasks = tasks.filter(task => task.id !== id);
    setTasks(updatedTasks);
    await saveTasks(updatedTasks);
  };

  const toggleTask = async (id) => {
    const updatedTasks = tasks.map(task =>
      task.id === id ? { ...task, completed: !task.completed } : task
    );
    setTasks(updatedTasks);
    await saveTasks(updatedTasks);
  };

  const startEdit = (task) => {
    setEditingId(task.id);
    setEditText(task.text);
  };

  const saveEdit = async (id) => {
    if (!editText.trim()) {
      deleteTask(id);
      return;
    }

    const updatedTasks = tasks.map(task =>
      task.id === id ? { ...task, text: editText.trim() } : task
    );
    setTasks(updatedTasks);
    await saveTasks(updatedTasks);
    setEditingId(null);
    setEditText('');
  };

  const cancelEdit = () => {
    setEditingId(null);
    setEditText('');
  };

  const clearCompleted = async () => {
    const updatedTasks = tasks.filter(task => !task.completed);
    setTasks(updatedTasks);
    await saveTasks(updatedTasks);
  };

  const filteredTasks = tasks.filter(task => {
    if (filter === 'active') return !task.completed;
    if (filter === 'completed') return task.completed;
    return true;
  });

  const totalTasks = tasks.length;
  const completedTasks = tasks.filter(t => t.completed).length;
  const activeTasks = totalTasks - completedTasks;

  // Добавим отладочный вывод в рендер
  console.log('Rendering with state:', { loading, tasks: tasks.length, error });

  if (loading) {
    return (
      <div className="app">
        <div className="loading">
          <div>Загрузка...</div>
          <div style={{ fontSize: '12px', marginTop: '10px', color: '#999' }}>
            Пожалуйста, подождите...
          </div>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="app">
        <div className="error-message" style={{
          padding: '20px',
          textAlign: 'center',
          color: '#dc3545',
          background: '#fff',
          borderRadius: '8px',
          margin: '20px'
        }}>
          <h3>Ошибка</h3>
          <p>{error}</p>
          <button 
            onClick={() => window.location.reload()}
            style={{
              padding: '10px 20px',
              background: '#2688eb',
              color: 'white',
              border: 'none',
              borderRadius: '5px',
              marginTop: '10px',
              cursor: 'pointer'
            }}
          >
            Перезагрузить
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="app">
      <header className="app-header">
        <h1>Мой список дел</h1>
        {userInfo && (
          <div className="user-info">
            <img 
              src={userInfo.photo_100} 
              alt={`${userInfo.first_name} ${userInfo.last_name}`}
              className="user-avatar"
              onError={(e) => {
                e.target.src = 'https://vk.com/images/camera_100.png';
              }}
            />
            <span className="user-name">
              {userInfo.first_name} {userInfo.last_name}
            </span>
          </div>
        )}
      </header>

      <main className="app-main">
        <form className="add-task-form" onSubmit={addTask}>
          <input
            type="text"
            value={newTask}
            onChange={(e) => setNewTask(e.target.value)}
            placeholder="Добавить новую задачу..."
            className="task-input"
          />
          <button type="submit" className="add-button">
            Добавить
          </button>
        </form>

        {tasks.length > 0 && (
          <div className="task-stats">
            <div className="stat-item">
              <span className="stat-label">Всего:</span>
              <span className="stat-value">{totalTasks}</span>
            </div>
            <div className="stat-item">
              <span className="stat-label">Активных:</span>
              <span className="stat-value">{activeTasks}</span>
            </div>
            <div className="stat-item">
              <span className="stat-label">Выполнено:</span>
              <span className="stat-value">{completedTasks}</span>
            </div>
          </div>
        )}

        <div className="filter-tabs">
          <button
            className={`filter-tab ${filter === 'all' ? 'active' : ''}`}
            onClick={() => setFilter('all')}
          >
            Все
          </button>
          <button
            className={`filter-tab ${filter === 'active' ? 'active' : ''}`}
            onClick={() => setFilter('active')}
          >
            Активные
          </button>
          <button
            className={`filter-tab ${filter === 'completed' ? 'active' : ''}`}
            onClick={() => setFilter('completed')}
          >
            Выполненные
          </button>
        </div>

        <div className="tasks-list">
          {filteredTasks.length === 0 ? (
            <div className="empty-state">
              {filter === 'all' && 'Список дел пуст. Добавьте первую задачу!'}
              {filter === 'active' && 'Нет активных задач'}
              {filter === 'completed' && 'Нет выполненных задач'}
            </div>
          ) : (
            filteredTasks.map(task => (
              <div
                key={task.id}
                className={`task-item ${task.completed ? 'completed' : ''}`}
              >
                {editingId === task.id ? (
                  <div className="task-edit">
                    <input
                      type="text"
                      value={editText}
                      onChange={(e) => setEditText(e.target.value)}
                      className="edit-input"
                      autoFocus
                      onKeyDown={(e) => {
                        if (e.key === 'Enter') saveEdit(task.id);
                        if (e.key === 'Escape') cancelEdit();
                      }}
                    />
                    <div className="edit-actions">
                      <button
                        onClick={() => saveEdit(task.id)}
                        className="save-button"
                        aria-label="Сохранить"
                      >
                        ✓
                      </button>
                      <button
                        onClick={cancelEdit}
                        className="cancel-button"
                        aria-label="Отмена"
                      >
                        ✗
                      </button>
                    </div>
                  </div>
                ) : (
                  <>
                    <div className="task-content">
                      <input
                        type="checkbox"
                        checked={task.completed}
                        onChange={() => toggleTask(task.id)}
                        className="task-checkbox"
                        aria-label={`Отметить задачу "${task.text}" как ${task.completed ? 'невыполненную' : 'выполненную'}`}
                      />
                      <span
                        className="task-text"
                        onDoubleClick={() => startEdit(task)}
                        title="Двойной клик для редактирования"
                      >
                        {task.text}
                      </span>
                    </div>
                    <div className="task-actions">
                      <button
                        onClick={() => startEdit(task)}
                        className="edit-button"
                        title="Редактировать"
                        aria-label="Редактировать"
                      >
                        ✎
                      </button>
                      <button
                        onClick={() => deleteTask(task.id)}
                        className="delete-button"
                        title="Удалить"
                        aria-label="Удалить"
                      >
                        ×
                      </button>
                    </div>
                  </>
                )}
              </div>
            ))
          )}
        </div>

        {completedTasks > 0 && (
          <button onClick={clearCompleted} className="clear-button">
            Очистить выполненные
          </button>
        )}
      </main>

      <footer className="app-footer">
        <p>Двойной клик по задаче - редактирование</p>
      </footer>
    </div>
  );
};

export default App;
